DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "PGchoicemacros.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context("Fraction");
Context()->noreduce('(-x)-y','(-x)+y');
$n = random(3,4);
$var = list_random('x','y','z','t');
@powers = (0..9)[NchooseK(10,$n)];
@ones = (1) x 90;
@ints = (2..91);
@decimals = map {$_ / 10} (1..9,11..19,21..29,31..39,41..49,51..59,61..69,71..79,81..89,91..99);
@fracs = ();
for my $j (2..10) {
  for my $i (1..10) {
    push(@fracs, Fraction($i,$j));
  }
}
@coefs = (@ones, @ints, @decimals, @fracs)[NchooseK(360,$n)];
@signs = (1,-1);
for my $i (2..$n) {
  push(@signs,list_random(-1,1))
}
@signs = (@signs)[NchooseK($n,$n)];
@coefs = map {$signs[$_-1]*$coefs[$_-1]} (1..$n);
Context()->variables->are($var => 'Real');
@terms = ();
for my $i (1..$n) {
  push(@terms, Formula("$coefs[$i-1]*$var^$powers[$i-1]")->reduce);
}
$ans = List(@terms);
$sum = Formula(join('+', @terms))->reduce;

############################################################
# Body
############################################################

BEGIN_PGML
List the terms in each expression.

[`[$sum]`]

[@KeyboardInstructions('Separate the terms in your list using commas.')@]**

[_]{$ans}{20}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
